/**
 * Ultimate Powerflow Card v1.5.0
 */

// ── Embedded images (injected at build time) ──────────────
const IMG = {
  day_grid:           "data:image/png;base64,",
  night_grid:         "data:image/png;base64,",
  day_solar:          "data:image/png;base64,",
  night_solar:        "data:image/png;base64,",
  day_solar_bat:      "data:image/png;base64,",
  night_solar_bat:    "data:image/png;base64,",
  day_solar_bat_ev:   "data:image/png;base64,",
  night_solar_bat_ev: "data:image/png;base64,",
};

function pickImage(day, solar, bat, ev) {
  const t = day ? "day" : "night";
  if (solar && bat && ev) return IMG[t + "_solar_bat_ev"];
  if (solar && bat)       return IMG[t + "_solar_bat"];
  if (solar)              return IMG[t + "_solar"];
  return IMG[t + "_grid"];
}

// ── Helpers ───────────────────────────────────────────────
function fmtW(w) {
  if (w === null || w === undefined || isNaN(w)) return "—";
  const a = Math.abs(w);
  if (a < 1000) return Math.round(a) + " W";
  const k = a / 1000;
  if (k < 10)  return k.toFixed(2) + " kW";
  if (k < 100) return k.toFixed(1) + " kW";
  return Math.round(k) + " kW";
}

function parseVal(s) {
  if (!s || s === "unavailable" || s === "unknown") return null;
  // Handle both European comma (2,27) and standard period (2.27) decimal format
  const normalized = String(s).trim().replace(/\s/g, "").replace(",", ".");
  const n = parseFloat(normalized);
  return isNaN(n) ? null : n;
}

function isDayTime(s) {
  return !s || s === "above_horizon";
}

function getWxType(c) {
  if (!c) return "none";
  const l = c.toLowerCase();
  if (l === "rainy" || l === "pouring" || l === "lightning-rainy") return "rain";
  if (l === "snowy" || l === "snowy-rainy" || l === "hail") return "snow";
  return "none";
}

// ── Weather canvas animations ─────────────────────────────
function startRain(canvas) {
  const ctx = canvas.getContext("2d");
  if (!ctx) return () => {};
  canvas.width  = canvas.offsetWidth  || 400;
  canvas.height = canvas.offsetHeight || 225;
  const drops = Array.from({ length: 80 }, () => ({
    x: Math.random() * canvas.width,
    y: Math.random() * canvas.height,
    len: 10 + Math.random() * 20,
    spd: 8  + Math.random() * 10,
    op:  0.2 + Math.random() * 0.3,
  }));
  let rafId = 0;
  const draw = () => {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    for (const d of drops) {
      ctx.beginPath();
      ctx.moveTo(d.x, d.y);
      ctx.lineTo(d.x - 1, d.y + d.len);
      ctx.strokeStyle = `rgba(174,214,241,${d.op})`;
      ctx.lineWidth = 1;
      ctx.stroke();
      d.y += d.spd;
      if (d.y > canvas.height) { d.y = -d.len; d.x = Math.random() * canvas.width; }
    }
    rafId = requestAnimationFrame(draw);
  };
  draw();
  return () => cancelAnimationFrame(rafId);
}

function startSnow(canvas) {
  const ctx = canvas.getContext("2d");
  if (!ctx) return () => {};
  canvas.width  = canvas.offsetWidth  || 400;
  canvas.height = canvas.offsetHeight || 225;
  const flakes = Array.from({ length: 55 }, () => ({
    x:   Math.random() * canvas.width,
    y:   Math.random() * canvas.height,
    r:   1.5 + Math.random() * 3,
    spd: 0.8 + Math.random() * 1.5,
    op:  0.4 + Math.random() * 0.4,
  }));
  let rafId = 0;
  const draw = () => {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    for (const f of flakes) {
      ctx.beginPath();
      ctx.arc(f.x, f.y, f.r, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(255,255,255,${f.op})`;
      ctx.fill();
      f.y += f.spd;
      f.x += Math.sin(f.y / 30) * 0.4;
      if (f.y > canvas.height) { f.y = -f.r * 2; f.x = Math.random() * canvas.width; }
    }
    rafId = requestAnimationFrame(draw);
  };
  draw();
  return () => cancelAnimationFrame(rafId);
}

// ── Energy flow calculator ────────────────────────────────
const THRESHOLD = 5;

function calcFlows(v) {
  const clamp = (n) => Math.max(0, n || 0);
  const solar = clamp(v.solar);
  const bch   = clamp(v.bch);
  const bdis  = clamp(v.bdis);
  const ev    = clamp(v.ev);
  const house = clamp(v.house);
  const load  = house + ev;

  const s2l  = Math.min(solar, load);
  const srem = solar - s2l;
  const s2b  = Math.min(srem, bch);
  const s2g  = Math.max(0, srem - s2b);
  const def  = load - s2l;
  const b2l  = Math.min(bdis, def);
  const g2l  = Math.max(0, def - b2l);
  const gimp = g2l > 1 ? g2l : Math.max(0, v.grid || 0);

  return {
    s2h:  load > 0 ? s2l * (house / load) : 0,
    s2b,
    s2g,
    b2h:  load > 0 ? b2l * (house / load) : 0,
    g2h:  gimp,
    h2ev: ev,
    gimp,
    gexp: s2g > 1 ? s2g : 0,
  };
}

// ── Cable route waypoints ─────────────────────────────────
// x = 0-100 (left→right), y = 0-100 (top→bottom) of the 16:9 card.
// These follow the white physical cables visible in the house images.
//
//  Solar panels:        x≈48  y≈26
//  Roof cable exit:     x≈57  y≈50
//  Meter / hub (⚡):    x≈57  y≈63
//  Battery (wall):      x≈51  y≈63
//  Ground cable run:    y≈75
//  Grid transformer:    x≈87  y≈67
//  EV charger pole:     x≈22  y≈70

const ROUTES = {
  solar_to_meter: [[48,26],[56,50],[57,63]],
  meter_to_bat:   [[57,63],[51,63]],
  meter_to_grid:  [[57,63],[57,75],[87,75],[87,67]],
  meter_to_ev:    [[57,63],[57,76],[22,76],[22,70]],
};

function buildSvgPath(routeKey, power, color, animCls, reversed) {
  const active = Math.abs(power) >= THRESHOLD;
  const pts    = reversed ? [...ROUTES[routeKey]].reverse() : ROUTES[routeKey];
  const d      = pts.map((c, i) => (i === 0 ? "M" : "L") + c[0] + " " + c[1]).join(" ");
  const cls    = active ? animCls : "fl-off";
  const glow   = active ? `filter:drop-shadow(0 0 4px ${color});` : "";
  return `<path class="${cls}" d="${d}" stroke="${color}" stroke-width="2.2" fill="none" stroke-linecap="round" stroke-linejoin="round" style="${glow}"/>`;
}

// ── Default positions & colors ────────────────────────────
const DEF_POS = {
  grid:  { x: 90, y: 85 },
  house: { x: 67, y: 75 },
  solar: { x: 50, y: 53 },
  bat:   { x: 60, y: 95 },
  ev:    { x: 11, y: 75 },
};

const DEF_COLORS = {
  grid: "#f5a623", solar: "#ffd700", battery: "#27ae60", household: "#5dade2", ev: "#a569bd",
};

// ── CSS ───────────────────────────────────────────────────
const CARD_CSS = `
  :host { display: block; }
  ha-card { overflow: hidden; background: #000; border-radius: var(--ha-card-border-radius, 12px); padding: 0; }
  .wrap { position: relative; width: 100%; padding-bottom: 56.25%; overflow: hidden; }
  .inner { position: absolute; inset: 0; }
  .bg { position: absolute; inset: 0; width: 100%; height: 100%; object-fit: cover; display: block; }
  .svg { position: absolute; inset: 0; width: 100%; height: 100%; z-index: 3; pointer-events: none; overflow: visible; }
  .wx { position: absolute; inset: 0; pointer-events: none; overflow: hidden; z-index: 2; }
  .wx canvas { width: 100%; height: 100%; opacity: .38; }

  /* Pure text labels — zero background, zero border */
  .lbl { position: absolute; transform: translate(-50%, -50%); z-index: 5; pointer-events: none; text-align: center; line-height: 1.3; }
  .lbl-name {
    display: block;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    font-size: 10px; font-weight: 600; letter-spacing: .07em; text-transform: uppercase;
    color: rgba(255,255,255,.8);
    text-shadow: 0 0 6px #000, 0 0 10px #000, 1px 1px 0 #000;
  }
  .lbl-val {
    display: block;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    font-size: 15px; font-weight: 800; color: #fff; white-space: nowrap;
    text-shadow: 0 0 6px #000, 0 0 14px #000, 0 0 22px #000, 1px 1px 0 #000;
  }
  .lbl-val.na { color: rgba(255,255,255,.4); font-size: 11px; }

  @keyframes fd { to { stroke-dashoffset: -36; } }
  .fl-act  { stroke-dasharray: 10 7; animation: fd  .9s linear infinite; }
  .fl-slow { stroke-dasharray: 10 7; animation: fd 1.8s linear infinite; }
  .fl-fast { stroke-dasharray: 10 7; animation: fd  .45s linear infinite; }
  .fl-off  { opacity: .08; }

  @media (max-width: 500px) {
    .lbl-val  { font-size: 11px; }
    .lbl-name { font-size: 8px; }
  }
`;

const EDITOR_CSS = `
  :host { display: block; }
  .sec { font-weight: 700; font-size: 11px; letter-spacing: .07em; text-transform: uppercase;
         color: var(--secondary-text-color); margin: 16px 0 8px; padding-bottom: 3px;
         border-bottom: 1px solid var(--divider-color, rgba(255,255,255,.1)); }
  .sec:first-child { margin-top: 0; }
  .row { display: flex; gap: 8px; margin-bottom: 8px; }
  .row > * { flex: 1; }
  .trow { display: flex; align-items: center; justify-content: space-between; padding: 5px 0; }
  .tlbl { font-size: 14px; color: var(--primary-text-color); }
  .cr { display: flex; gap: 10px; flex-wrap: wrap; margin-top: 8px; }
  .ci { display: flex; flex-direction: column; align-items: center; gap: 3px; font-size: 11px; color: var(--secondary-text-color); }
  .ci input[type=color] { width: 40px; height: 28px; border: none; background: none; cursor: pointer; border-radius: 6px; }
  .sel { width: 100%; background: var(--card-background-color, #1c1c2e); color: var(--primary-text-color);
         border: 1px solid var(--divider-color, rgba(255,255,255,.2)); border-radius: 4px; padding: 8px; font-size: 14px; margin-top: 4px; }
  .pgrid { display: grid; grid-template-columns: 1fr 1fr; gap: 8px; margin-top: 4px; }
`;

// ── Main Card element ─────────────────────────────────────
class UltimatePowerflowCard extends HTMLElement {

  static get properties() { return {}; }

  static getConfigElement() {
    return document.createElement("ultimate-powerflow-card-editor");
  }

  static getStubConfig() {
    return { grid_power_entity: "sensor.grid_power", household_power_entity: "sensor.household_power" };
  }

  constructor() {
    super();
    this.attachShadow({ mode: "open" });
    this._config   = null;
    this._hass     = null;
    this._stopWx   = null;
    this._wxType   = "none";
    this._ro       = null;
  }

  setConfig(config) {
    if (!config.grid_power_entity)      throw new Error("ultimate-powerflow-card: grid_power_entity is required");
    if (!config.household_power_entity) throw new Error("ultimate-powerflow-card: household_power_entity is required");
    this._config = {
      sun_entity:        "sun.sun",
      animation_speed:   "normal",
      solar_enabled:     false,
      battery_enabled:   false,
      ev_charger_enabled: false,
      ...config,
    };
    this._render();
  }

  set hass(hass) {
    this._hass = hass;
    if (this._config) this._render();
  }

  connectedCallback() {
    this._ro = new ResizeObserver(() => {
      if (this._stopWx) { this._stopWx(); this._stopWx = null; }
      this._startWeather();
    });
    this._ro.observe(this);
  }

  disconnectedCallback() {
    if (this._stopWx) this._stopWx();
    if (this._ro)    this._ro.disconnect();
  }

  getCardSize() { return 4; }

  // ── Private helpers ───────────────────────────────────

  _stateOf(entityId) {
    if (!entityId || !this._hass) return undefined;
    const e = this._hass.states[entityId];
    return e ? e.state : undefined;
  }

  _colors() {
    return { ...DEF_COLORS, ...(this._config.colors || {}) };
  }

  _pos(key) {
    return (this._config.label_positions && this._config.label_positions[key]) || DEF_POS[key];
  }

  _animCls() {
    const sp = this._config.animation_speed || "normal";
    return sp === "slow" ? "fl-slow" : sp === "fast" ? "fl-fast" : "fl-act";
  }

  _label(key, name, value) {
    const p  = this._pos(key);
    const dv = value === null ? "—" : fmtW(value);
    const na = value === null ? " na" : "";
    return `<div class="lbl" style="left:${p.x}%;top:${p.y}%">` +
           `<span class="lbl-name">${name}</span>` +
           `<span class="lbl-val${na}">${dv}</span>` +
           `</div>`;
  }

  _render() {
    if (!this._config) return;
    const cfg = this._config;
    const col = this._colors();
    const ac  = this._animCls();

    // Sensor values
    const gv   = parseVal(this._stateOf(cfg.grid_power_entity));
    const hv   = parseVal(this._stateOf(cfg.household_power_entity));
    const sv   = cfg.solar_enabled      ? parseVal(this._stateOf(cfg.solar_power_entity))               : null;
    const bch  = cfg.battery_enabled    ? parseVal(this._stateOf(cfg.battery_charging_power_entity))    : null;
    const bdis = cfg.battery_enabled    ? parseVal(this._stateOf(cfg.battery_discharging_power_entity)) : null;
    const ev   = cfg.ev_charger_enabled ? parseVal(this._stateOf(cfg.ev_charger_power_entity))          : null;

    const flows = calcFlows({ solar: sv || 0, bch: bch || 0, bdis: bdis || 0, ev: ev || 0, house: hv || 0, grid: gv || 0 });

    // Image
    const img = pickImage(
      isDayTime(this._stateOf(cfg.sun_entity || "sun.sun")),
      !!cfg.solar_enabled, !!cfg.battery_enabled, !!cfg.ev_charger_enabled
    );

    // Weather overlay
    const wx = getWxType(this._stateOf(cfg.weather_entity));
    const wxHtml = wx === "rain"
      ? `<div class="wx"><canvas class="rxc"></canvas></div>`
      : wx === "snow"
      ? `<div class="wx"><canvas class="sxc"></canvas></div>`
      : "";

    // SVG flow lines
    const totalSolar = flows.s2h + flows.s2b + flows.s2g;
    const totalBat   = flows.s2b + flows.b2h;
    const lines = [
      buildSvgPath("meter_to_grid",  flows.gimp,   col.grid,    ac, false),
      cfg.solar_enabled      ? buildSvgPath("solar_to_meter", totalSolar,   col.solar,   ac, false) : "",
      cfg.battery_enabled    ? buildSvgPath("meter_to_bat",   totalBat,     col.battery, ac, flows.b2h > flows.s2b) : "",
      cfg.ev_charger_enabled ? buildSvgPath("meter_to_ev",    flows.h2ev,   col.ev,      ac, false) : "",
    ].join("");

    // Battery display: prefer charging, else discharging
    const batVal = (bch || 0) > 0 ? bch : bdis !== null ? bdis : null;

    // Labels
    const labels = [
      this._label("grid",  "Grid",    gv !== null ? Math.abs(gv) : null),
      this._label("house", "Thuis",   hv),
      cfg.solar_enabled      ? this._label("solar", "Panelen", sv)     : "",
      cfg.battery_enabled    ? this._label("bat",   "Batterij",batVal) : "",
      cfg.ev_charger_enabled ? this._label("ev",    "EV",      ev)     : "",
    ].join("");

    this.shadowRoot.innerHTML =
      `<style>${CARD_CSS}</style>` +
      `<ha-card>` +
        `<div class="wrap"><div class="inner">` +
          `<img class="bg" src="${img}" alt=""/>` +
          wxHtml +
          `<svg class="svg" viewBox="0 0 100 100" preserveAspectRatio="none">${lines}</svg>` +
          labels +
        `</div></div>` +
      `</ha-card>`;

    // Update weather animation
    if (wx !== this._wxType) {
      if (this._stopWx) { this._stopWx(); this._stopWx = null; }
      this._wxType = wx;
    }
    this._startWeather();
  }

  _startWeather() {
    if (this._wxType === "rain") {
      const c = this.shadowRoot && this.shadowRoot.querySelector(".rxc");
      if (c && !this._stopWx) this._stopWx = startRain(c);
    } else if (this._wxType === "snow") {
      const c = this.shadowRoot && this.shadowRoot.querySelector(".sxc");
      if (c && !this._stopWx) this._stopWx = startSnow(c);
    }
  }
}

// ── Editor element ────────────────────────────────────────
class UltimatePowerflowCardEditor extends HTMLElement {

  constructor() {
    super();
    this.attachShadow({ mode: "open" });
    this._config = {};
    this._hass   = null;
  }

  set hass(h) {
    this._hass = h;
    this.shadowRoot.querySelectorAll("ha-entity-picker").forEach((el) => (el.hass = h));
  }

  setConfig(config) {
    this._config = { ...config };
    this._render();
  }

  _fire() {
    this.dispatchEvent(new CustomEvent("config-changed", { detail: { config: this._config }, bubbles: true, composed: true }));
  }

  _set(key, value, skipRender) {
    const parts = key.split(".");
    if (parts.length === 3 && parts[0] === "lp") {
      const lp = { ...(this._config.label_positions || {}) };
      lp[parts[1]] = { ...(lp[parts[1]] || {}), [parts[2]]: parseFloat(value) };
      this._config = { ...this._config, label_positions: lp };
    } else if (parts.length === 2) {
      this._config = { ...this._config, [parts[0]]: { ...(this._config[parts[0]] || {}), [parts[1]]: value } };
    } else {
      this._config = { ...this._config, [key]: value };
    }
    this._fire();
    if (!skipRender) this._render();
  }

  _render() {
    const c   = this._config;
    const col = c.colors || {};
    const pos = c.label_positions || {};

    const ep = (label, key, val) =>
      `<div class="row"><ha-entity-picker label="${label}" value="${val || ""}" data-key="${key}" allow-custom-entity></ha-entity-picker></div>`;

    const sw = (label, key) =>
      `<div class="trow"><span class="tlbl">${label}</span><ha-switch data-key="${key}"${c[key] ? " checked" : ""}></ha-switch></div>`;

    const tf = (label, key, val) =>
      `<ha-textfield label="${label}" type="number" value="${val !== undefined ? val : ""}" data-key="${key}"></ha-textfield>`;

    this.shadowRoot.innerHTML =
      `<style>${EDITOR_CSS}</style>` +
      `<div class="sec">&#9889; Core Entities</div>` +
      ep("Grid Power *",       "grid_power_entity",      c.grid_power_entity) +
      ep("Household Power *",  "household_power_entity", c.household_power_entity) +
      ep("Sun Entity",         "sun_entity",             c.sun_entity || "sun.sun") +
      `<div class="sec">&#128268; Optional Devices</div>` +
      sw("&#9728;&#65039; Solar Panels", "solar_enabled") +
      (c.solar_enabled ? ep("Solar Power", "solar_power_entity", c.solar_power_entity) : "") +
      sw("&#128267; Battery", "battery_enabled") +
      (c.battery_enabled
        ? ep("Charging Power",   "battery_charging_power_entity",    c.battery_charging_power_entity) +
          ep("Discharging Power","battery_discharging_power_entity",  c.battery_discharging_power_entity)
        : "") +
      sw("&#128663; EV Charger", "ev_charger_enabled") +
      (c.ev_charger_enabled ? ep("EV Power", "ev_charger_power_entity", c.ev_charger_power_entity) : "") +
      ep("Weather Entity (optional)", "weather_entity", c.weather_entity) +
      `<div class="sec">&#127912; Appearance</div>` +
      `<label style="font-size:13px;color:var(--secondary-text-color)">Animation Speed</label>` +
      `<select class="sel" data-key="animation_speed">` +
        `<option value="slow"${c.animation_speed==="slow"?" selected":""}>Slow</option>` +
        `<option value="normal"${!c.animation_speed||c.animation_speed==="normal"?" selected":""}>Normal</option>` +
        `<option value="fast"${c.animation_speed==="fast"?" selected":""}>Fast</option>` +
      `</select><br/><br/>` +
      `<label style="font-size:13px;color:var(--secondary-text-color)">Flow Colors</label>` +
      `<div class="cr">` +
        `<div class="ci"><input type="color" value="${col.grid||"#f5a623"}" data-key="colors.grid"/><span>Grid</span></div>` +
        `<div class="ci"><input type="color" value="${col.solar||"#ffd700"}" data-key="colors.solar"/><span>Solar</span></div>` +
        `<div class="ci"><input type="color" value="${col.battery||"#27ae60"}" data-key="colors.battery"/><span>Battery</span></div>` +
        `<div class="ci"><input type="color" value="${col.household||"#5dade2"}" data-key="colors.household"/><span>House</span></div>` +
        (c.ev_charger_enabled ? `<div class="ci"><input type="color" value="${col.ev||"#a569bd"}" data-key="colors.ev"/><span>EV</span></div>` : "") +
      `</div>` +
      `<div class="sec">&#128295; Label Positions (% &#8212; optioneel)</div>` +
      `<div class="pgrid">` +
        tf("Grid X",  "lp.grid.x",  pos.grid  && pos.grid.x  !== undefined ? pos.grid.x  : "") +
        tf("Grid Y",  "lp.grid.y",  pos.grid  && pos.grid.y  !== undefined ? pos.grid.y  : "") +
        tf("House X", "lp.house.x", pos.house && pos.house.x !== undefined ? pos.house.x : "") +
        tf("House Y", "lp.house.y", pos.house && pos.house.y !== undefined ? pos.house.y : "") +
        (c.solar_enabled
          ? tf("Solar X","lp.solar.x", pos.solar&&pos.solar.x!==undefined?pos.solar.x:"") +
            tf("Solar Y","lp.solar.y", pos.solar&&pos.solar.y!==undefined?pos.solar.y:"")
          : "") +
        (c.battery_enabled
          ? tf("Battery X","lp.bat.x", pos.bat&&pos.bat.x!==undefined?pos.bat.x:"") +
            tf("Battery Y","lp.bat.y", pos.bat&&pos.bat.y!==undefined?pos.bat.y:"")
          : "") +
        (c.ev_charger_enabled
          ? tf("EV X","lp.ev.x", pos.ev&&pos.ev.x!==undefined?pos.ev.x:"") +
            tf("EV Y","lp.ev.y", pos.ev&&pos.ev.y!==undefined?pos.ev.y:"")
          : "") +
      `</div>`;

    // Bind events
    this.shadowRoot.querySelectorAll("ha-entity-picker").forEach((el) => {
      el.hass = this._hass;
      el.addEventListener("value-changed", (e) => { if (el.dataset.key) this._set(el.dataset.key, e.detail.value); });
    });
    this.shadowRoot.querySelectorAll("ha-switch").forEach((el) => {
      el.addEventListener("change", (e) => { if (el.dataset.key) this._set(el.dataset.key, e.target.checked); });
    });
    this.shadowRoot.querySelectorAll("ha-textfield").forEach((el) => {
      // skipRender=true so typing doesn't kick focus out by re-rendering
      el.addEventListener("input", (e) => { if (el.dataset.key) this._set(el.dataset.key, e.target.value, true); });
    });
    this.shadowRoot.querySelectorAll("select").forEach((el) => {
      el.addEventListener("change", (e) => { if (el.dataset.key) this._set(el.dataset.key, e.target.value); });
    });
    this.shadowRoot.querySelectorAll("input[type=color]").forEach((el) => {
      el.addEventListener("input", (e) => { if (el.dataset.key) this._set(el.dataset.key, e.target.value, true); });
    });
  }
}

// ── Register ──────────────────────────────────────────────
if (!customElements.get("ultimate-powerflow-card"))
  customElements.define("ultimate-powerflow-card", UltimatePowerflowCard);
if (!customElements.get("ultimate-powerflow-card-editor"))
  customElements.define("ultimate-powerflow-card-editor", UltimatePowerflowCardEditor);

window.customCards = window.customCards || [];
if (!window.customCards.find((c) => c.type === "ultimate-powerflow-card")) {
  window.customCards.push({
    type: "ultimate-powerflow-card",
    name: "Ultimate Powerflow Card",
    description: "Animated energy flow over a photorealistic house image.",
    preview: true,
  });
}

console.info(
  "%c ULTIMATE-POWERFLOW-CARD %c v1.5.0 ",
  "background:#1a1a2e;color:#ffd700;font-weight:700;padding:2px 6px;border-radius:3px 0 0 3px",
  "background:#ffd700;color:#1a1a2e;font-weight:700;padding:2px 6px;border-radius:0 3px 3px 0"
);
